const today = new Date();
const items = [];

for (const item of $input.all()) {
  const row = item.json;
  const declined = new Date(row.DeclineDate);
  const daysDiff = Math.floor((today - declined) / (1000 * 60 * 60 * 24));

  let sendText = false;
  let day = null;

  if (daysDiff >= 90 && row.Sent90 === 'FALSE') {
    sendText = true; day = 90;
  } else if (daysDiff >= 60 && row.Sent60 === 'FALSE') {
    sendText = true; day = 60;
  } else if (daysDiff >= 30 && row.Sent30 === 'FALSE') {
    sendText = true; day = 30;
  }

  if (sendText) {
    items.push({ json: { ...row, sendDay: day, daysDiff } });
  }
}

return items;
